pub fn disable_interrupts() -> bool {
    let sie = riscv::register::sstatus::read().sie();
    if sie {
        unsafe {
            riscv::register::sstatus::clear_sie();
        }
    }
    sie
}

pub fn restore_interrupts(was_enabled: bool) {
    if was_enabled {
        unsafe {
            riscv::register::sstatus::set_sie();
        }
    }
}

