pub fn init() {
    set_kernel_trap_entry();

    // 我们使用 SBI 轮询 (console_getchar) 来读取输入，不需要处理 PLIC 中断。
    // 如果开启而不处理 (Claim/Complete)，会导致中断风暴卡死系统。
    unsafe {
        riscv::register::sie::clear_sext();
    }
}

fn set_kernel_trap_entry() {
    unsafe {
        // 修改：使用 __kernelvec 作为内核陷阱入口
        stvec::write(__kernelvec as usize, TrapMode::Direct);
    }
}

fn set_user_trap_entry() {
    unsafe {
        stvec::write(TRAMPOLINE as usize, TrapMode::Direct);
    }
}

pub fn enable_timer_interrupt() {
    unsafe {
        sie::set_stimer();
    }
}

#[no_mangle]
pub fn trap_handler() -> ! {
    set_kernel_trap_entry();

    // 【关键检查】验证 tp 寄存器有效
    // 如果 tp 无效，说明 kernel_tp 没有正确设置
    let raw_tp: usize;
    unsafe {
        core::arch::asm!("mv {}, tp", out(reg) raw_tp);
    }
    if raw_tp >= crate::config::MAX_CPU_NUM {
        let sepc_val = sepc::read();
        let scause_val = scause::read();
        let stval_val = stval::read();
        panic!(
            "[trap_handler] Invalid tp={} (should be < {}). sepc={:#x} scause={:?} stval={:#x}",
            raw_tp,
            crate::config::MAX_CPU_NUM,
            sepc_val,
            scause_val.cause(),
            stval_val
        );
    }

    let scause = scause::read();
    let stval = stval::read();
    let mut skip_time_accounting = false;

    if !matches!(scause.cause(), Trap::Exception(Exception::UserEnvCall)) {
        // 安全地记录时间，仅当有任务时
        if let Some(task) = current_task() {
            let mut inner = task.acquire_inner_lock();
            inner.update_process_times_enter_trap();
        }
    }

    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // 1. 获取系统调用 ID 和参数
            // 使用单独的块 {} 限制作用域，确保 task 变量在 syscall 之前被 Drop
            // 否则 sys_exit 挂起时，栈上会残留 task 的引用，导致引用计数无法清零
            let (syscall_id, args) = if let Some(task) = current_task() {
                let mut inner = task.acquire_inner_lock();
                let (syscall_id, args) = {
                    let cx = inner.get_trap_cx();
                    cx.origin_a0 = cx.gp.a0;
                    cx.gp.pc += 4; // 跳过 ecall 指令
                    (
                        cx.gp.a7,
                        [cx.gp.a0, cx.gp.a1, cx.gp.a2, cx.gp.a3, cx.gp.a4, cx.gp.a5],
                    )
                };
                skip_time_accounting = crate::syscall::is_fast_syscall(syscall_id);
                if !skip_time_accounting {
                    inner.update_process_times_enter_trap();
                }
                (syscall_id, args)
            } else {
                // 之前添加的 Panic 调试信息
                let raw_tp: usize;
                unsafe {
                    core::arch::asm!("mv {}, tp", out(reg) raw_tp);
                }
                panic!(
                    "Syscall from Idle is impossible! tp={}, cpu_id={}",
                    raw_tp,
                    crate::task::processor::current_cpu_id()
                );
            };
            // ^^^ 关键点：在这里，'task' 变量离开作用域被 Drop，引用计数恢复正常

            // 2. 执行系统调用
            // 此时栈上不再持有当前任务的强引用
            // 如果是 sys_exit，它将不会返回，但因为 task 已被释放，wait4 可以正常回收资源
            let result = syscall(syscall_id, args);

            // 3. 处理返回值
            // 只有当 syscall 返回时（即不是 exit），才会执行到这里
            // 重新获取任务上下文写入返回值
            if let Some(task) = current_task() {
                let mut inner = task.acquire_inner_lock();
                let cx = inner.get_trap_cx();
                cx.gp.a0 = result as usize;
                inner.syscall_restart_pending = result == ERESTART;
            }
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            if let Some(task) = current_task() {
                let addr = VirtAddr::from(stval);
                log::trace!(
                    "[page_fault] pid: {}, type: {:?}",
                    task.pid.0,
                    scause.cause()
                );
                // 关键修复：先处理内存映射（持有 vm lock），再处理信号（持有 inner lock）
                // 避免锁嵌套导致的死锁
                frame_reserve(3);
                let access = match scause.cause() {
                    Trap::Exception(Exception::StoreFault)
                    | Trap::Exception(Exception::StorePageFault) => PageFaultAccess::Write,
                    Trap::Exception(Exception::InstructionFault)
                    | Trap::Exception(Exception::InstructionPageFault) => PageFaultAccess::Execute,
                    Trap::Exception(Exception::LoadFault)
                    | Trap::Exception(Exception::LoadPageFault) => PageFaultAccess::Read,
                    _ => unreachable!(),
                };
                let page_fault_result =
                    { task.vm.lock().do_page_fault_with_access(addr, Some(access)) };

                if let Err(error) = page_fault_result {
                    let mut inner = task.acquire_inner_lock();
                    match error {
                        MemoryError::BeyondEOF => {
                            inner.add_signal(Signals::SIGBUS);
                        }
                        MemoryError::NoPermission
                        | MemoryError::BadAddress
                        | MemoryError::NoMemory
                        | MemoryError::AlreadyAllocated
                        | MemoryError::AlreadyMapped => {
                            inner.add_signal(Signals::SIGSEGV);
                        }
                        _ => unreachable!(),
                    }
                };
            } else {
                panic!(
                    "Kernel PageFault in Idle/Init! scause: {:?}, stval: {:#x}",
                    scause.cause(),
                    stval
                );
            }
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            if let Some(task) = current_task() {
                let mut inner = task.acquire_inner_lock();
                inner.add_signal(Signals::SIGILL);
            } else {
                panic!("IllegalInstruction in Idle!");
            }
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            if unsafe { TIMER_INTERRUPT } % 100 == 0 {
                log::trace!("[Trap] Timer interrupt triggered");
            }

            let expired = do_wake_expired();
            crate::fs::dev::interrupts::Interrupts::increment_interrupt_count(5);
            set_next_trigger();

            // 即使没有 ready task 或 expired timer，也进入调度器让 cyclictest
            // 这类 timer-wakeup 基准能及时被调度。条件式抢占会引入额外一个 tick
            // 的延迟（~1ms），对 cyclictest 的

