    pub t4: usize,
    pub t5: usize,
    pub t6: usize,
}

/// FP registers
#[repr(C)]
#[derive(Debug, Default, Clone, Copy)]
pub struct FloatRegs {
    pub f: [usize; 32],
    pub fcsr: u32,
}

#[repr(C, align(16))]
#[derive(Debug, Clone, Copy)]
pub struct MachineFloatContext {
    pub f: [usize; 64],
    pub fcsr: u32,
    pub reserved: [u32; 3],
}

impl Default for MachineFloatContext {
    fn default() -> Self {
        Self {
            f: [0; 64],
            fcsr: 0,
            reserved: [0; 3],
        }
    }
}

#[repr(C, align(16))]
#[derive(Default, Debug, Clone, Copy)]
pub struct MachineContext {
    gp: GeneralRegs,
    fp: MachineFloatContext,
}

impl MachineContext {
    pub fn from_trap_context(cx: &TrapContext) -> Self {
        let mut fp = MachineFloatContext::default();
        fp.f[..32].copy_from_slice(&cx.fp.f);
        fp.fcsr = cx.fp.fcsr;
        Self { gp: cx.gp, fp }
    }

    pub fn restore_to_trap_context(&self, cx: &mut TrapContext) {
        cx.gp = self.gp;
        cx.fp.f.copy_from_slice(&self.fp.f[..32]);
        cx.fp.fcsr = self.fp.fcsr;
    }
}

