const FUTEX_WAITERS: u32 = 0x8000_0000;
const FUTEX_OWNER_DIED: u32 = 0x4000_0000;
const FUTEX_TID_MASK: u32 = 0x3fff_ffff;
const ROBUST_LIST_LIMIT: usize = 2048;

fn translated_ref_nofault<T>(token: usize, ptr: *const T) -> Result<&'static T, isize> {
    let page_table = PageTableImpl::from_token(token);
    let va = VirtAddr::from(ptr as usize);
    match page_table.translate_va(va) {
        Some(pa) => Ok(pa.get_ref()),
        None => Err(crate::syscall::errno::EFAULT),
    }
}

fn translated_refmut_nofault<T>(token: usize, ptr: *mut T) -> Result<&'static mut T, isize> {
    let page_table = PageTableImpl::from_token(token);
    let va = VirtAddr::from(ptr as usize);
    match page_table.translate_va(va) {
        Some(pa) => Ok(pa.get_mut()),
        None => Err(crate::syscall::errno::EFAULT),
    }
}

fn handle_robust_futex(
    task: &Arc<TaskControlBlock>,
    user_token: usize,
    entry_addr: usize,
    futex_offset: isize,
) {
    let futex_addr = match (entry_addr as isize).checked_add(futex_offset) {
        Some(addr) if addr >= 0 => addr as usize,
        _ => return,
    };

    let futex_word = match translated_refmut_nofault(user_token, futex_addr as *mut u32) {
        Ok(word) => word,
        Err(_) => return,
    };

    let word = *futex_word;
    if (word & FUTEX_TID_MASK) != (task.pid.0 as u32 & FUTEX_TID_MASK) {
        return;
    }

    *futex_word = (word & FUTEX_WAITERS) | FUTEX_OWNER_DIED;
    let futex_word_addr = futex_word as *const u32 as usize;
    task.futex.lock().wake(futex_word_addr, 1);
    threads::SHARED_FUTEX.lock().wake(futex_word_addr, 1);
}

fn release_robust_futexes(
    task: &Arc<TaskControlBlock>,
    user_token: usize,
    robust_list: RobustList,
) {
    if robust_list.head == 0 {
        return;
    }

    let head = match translated_ref_nofault(user_token, robust_list.head as *const RobustListHead) {
        Ok(head) => *head,
        Err(_) => return,
    };

    let head_list_addr = robust_list.head;
    let mut entry_addr = head.list.next;
    let mut seen = 0usize;

    while entry_addr != 0 && entry_addr != head_list_addr && seen < ROBUST_LIST_LIMIT {
        let entry = match translated_ref_nofault(user_token, entry_addr as *const RobustListEntry) {
            Ok(entry) => *entry,
            Err(_) => break,
        };
        handle_robust_futex(task, user_token, entry_addr, head.futex_offset);
        entry_addr = entry.next;
        seen += 1;
    }

    if head.list_op_pending != 0 {
        handle_robust_futex(task, user_token, head.list_op_pending, head.futex_offset);
    }
}

fn release_exit_file_refs(task: &Arc<TaskControlBlock>) {
    crate::syscall::fs::remove_task_fd_modes(task.pid.0);
    task.socket_table.lock().clear();

    if Arc::strong_count(&task.files) == 1 {
        let mut files = task.files.lock();
        crate::syscall::fs::remove_task_file_runtime_state(task.pid.0, &files);
        files.clear();
    }
    if Arc::strong_count(&task.fs) == 1 {
        task.fs.lock().working_inode = ROOT_FD.clone();
    }
    if Arc::strong_count(&task.exe) == 1 {
        *task.exe.lock() = ROOT_FD.as_ref().clone();
    }
}

fn release_group_shared_file_refs_if_private(
    current: &Arc<TaskControlBlock>,
    exiting_tasks: &[Arc<TaskControlBlock>],
) {
    let group_file_refs = 1 + exiting_tasks
        .iter()
        .filter(|task| Arc::ptr_eq(&task.files, &current.files))
        .count();
    if Arc::strong_count(&current.files) == group_file_refs {
        current.files.lock().clear();
    }
}

#[allow(unused)]
pub fn try_yield() {
    let cpu_id = current_cpu_id();
    let lock = PROCESSORS[cpu_id].lock();
    let mut do_suspend = false;
    if !lock.is_vacant() {
        do_suspend = true;
    }
    drop(lock);
    if do_suspend {
        suspend_current_and_run_next()
    }
}

pub fn suspend_current_and_run_next() {
    let _guard = InterruptGuard::new();
    let cpu_id = processor::current_cpu_id();

    if let Some(task) = take_current_task() {
        let task_cx_ptr = {
            let mut task_inner = task.acquire_inner_lock();
            let ptr = &mut task_inner.task_cx as *mut TaskContext;
            task_inner.task_status = TaskStatus::Ready;
            ptr
        };

        // 【关键修复】不直接add_task，而是设置pending_task
        // 这样任务上下文会在__switch时保存，之后才被加入就绪队列
        // 避免其他CPU在上下文保存前就偷取任务导致竞争
        {
            let mut processor = processor::PROCESSORS[cpu_id].lock();
            processor.set_pending(task);
        }

        schedule(task_cx_ptr);

        // Debug: check ra after resuming from schedule (RISC-V only)
        #[cfg(target_arch = "riscv64")]
        {
            let ra_after: usize;
            unsafe {
                core::arch::asm!("mv {}, ra", out(reg) ra_after);
            }
            if ra_after == 0 {
                panic!(
                    "[CPU {}] suspend_current_and_run_next: ra=0 after schedule()!",
                    cpu_id
                );
            }
        }
    }
}

pub fn block_current_and_run_next() {
    let _guard = InterruptGuard::new();
    let cpu_id = processor::current_cpu_id();

    let task = take_current_task().unwrap();

    let task_cx_ptr = {
        let mut task_inner = task.acquire_inner_lock();
        let ptr = &mut task_inner.task_cx as *mut TaskContext;
        if task_inner.task_status != TaskStatus::Ready {
            task_inner.task_status = TaskStatus::Interruptible;
        }
        ptr
    };

    // 【关键修复】不直接 sleep_interruptible，而是设置 pending_task
    // 这样任务上下文会在 __switch 时保存，之后才被加入睡眠队列
    // 避免其他CPU在上下文保存前就唤醒并运行任务导致竞争
    {
        let mut processor = processor::PROCESSORS[cpu_id].lock();
        processor.set_pending(task);
    }

    // 在 schedule 之后, run_tasks 会检测到 pending_task
    // 但 block 不是加入 ready 队列，而是加入 interruptible 队列
    // 所以需要标记这个 task 是要 block 而不是 ready
    schedule(task_cx_ptr);
}

pub fn stop_current_and_run_next() {
    let _guard = InterruptGuard::new();
    let cpu_id = processor::current_cpu_id();

    let task = take_current_task().unwrap();

    let task_cx_ptr = {
        let mut task_inner = task.acquire_inner_lock();
        let ptr = &mut task_inner.task_cx as *mut TaskContext;
        task_inner.task_status = TaskStatus::Stopped;
        ptr
    };

    {
        let mut processor = processor::PROCESSORS[cpu_id].lock();
        processor.set_pending(task);
    }

    schedule(task_cx_ptr);
}

