/// Page table trait defining core operations
#[allow(unused)]
pub trait PageTable {
    /// Map virtual page number to physical page number with given permissions
    ///
    /// # Panics
    /// Panics if the `vpn` is already mapped
    ///
    /// # Note
    /// Frame allocation should be done elsewhere
    fn map(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, flags: MapPermission);
    #[inline(always)]
    fn map_identical(&mut self, vpn: VirtPageNum, ppn: PhysPageNum, flags: MapPermission) {
        self.map(vpn, ppn, flags)
    }

    /// Unmap a virtual page number
    ///
    /// # Panics
    /// Panics if the `vpn` is NOT mapped
    #[allow(unused)]
    fn unmap(&mut self, vpn: VirtPageNum);

    #[inline(always)]
    fn unmap_identical(&mut self, vpn: VirtPageNum) {
        self.unmap(vpn)
    }

    /// Translate virtual page number to physical page number
    ///
    /// Returns `None` if not mapped
    fn translate(&self, vpn: VirtPageNum) -> Option<PhysPageNum>;

    /// Translate virtual address to physical address
    ///
    /// Returns `None` if not mapped
    fn translate_va(&self, va: VirtAddr) -> Option<PhysAddr>;

    fn block_and_ret_mut(&self, vpn: VirtPageNum) -> Option<PhysPageNum>;

    /// Return the page table token (satp register value)
    fn token(&self) -> usize;

    fn revoke_read(&mut self, vpn: VirtPageNum) -> Result<(), ()>;
    fn revoke_write(&mut self, vpn: VirtPageNum) -> Result<(), ()>;
    fn revoke_execute(&mut self, vpn: VirtPageNum) -> Result<(), ()>;
    fn set_ppn(&mut self, vpn: VirtPageNum, ppn: PhysPageNum) -> Result<(), ()>;
    fn set_pte_flags(&mut self, vpn: VirtPageNum, flags: MapPermission) -> Result<(), ()>;
    fn clear_access_bit(&mut self, vpn: VirtPageNum) -> Result<(), ()>;
    fn clear_dirty_bit(&mut self, vpn: VirtPageNum) -> Result<(), ()>;

    fn new() -> Self;

    #[inline(always)]
    fn new_kern_space() -> Self
    where
        Self: Sized,
    {
        Self::new()
    }

    /// Create a page table from satp token
    ///
    /// # Arguments
    /// * `satp` - Supervisor Address Translation & Protection register value
    fn from_token(satp: usize) -> Self;

    /// Check if a virtual page is mapped
    fn is_mapped(&mut self, vpn: VirtPageNum) -> bool;

    /// Activate this page table (switch to it)
    fn activate(&self);

    fn is_valid(&self, vpn: VirtPageNum) -> Option<bool>;
    fn is_dirty(&self, vpn: VirtPageNum) -> Option<bool>;
    fn readable(&self, vpn: VirtPageNum) -> Option<bool>;
    fn writable(&self, vpn: VirtPageNum) -> Option<bool>;
    fn executable(&self, vpn: VirtPageNum) -> Option<bool>;
    fn user_accessible(&self, vpn: VirtPageNum) -> Option<bool>;
}

/// Generate start and end page numbers from virtual addresses
#[allow(unused)]
pub fn gen_start_end(start: VirtAddr, end: VirtAddr) -> (VirtPageNum, VirtPageNum) {
    (start.floor(), end.ceil())
}

fn checked_user_range(addr: usize, len: usize) -> Result<usize, isize> {
    if len == 0 {
        return Ok(addr);
    }
    if addr < PAGE_SIZE {
        return Err(EFAULT);
    }
    addr.checked_add(len).ok_or(EFAULT)
}

#[derive(Clone, Copy)]
enum UserAccess {
    Read,
    Write,
}

impl UserAccess {
    fn page_fault_access(self) -> PageFaultAccess {
        match self {
            UserAccess::Read => PageFaultAccess::Read,
            UserAccess::Write => PageFaultAccess::Write,
        }
    }
}

fn page_allows_user_access(
    page_table: &super::PageTableImpl,
    vpn: VirtPageNum,
    access: UserAccess,
) -> bool {
    if page_table.user_accessible(vpn) != Some(true) {
        return false;
    }
    match access {
        UserAccess::Read => page_table.readable(vpn) == Some(true),
        UserAccess::Write => page_table.writable(vpn) == Some(true),
    }
}

fn translate_user_va(
    page_table: &super::PageTableImpl,
    va: VirtAddr,
    access: UserAccess,
) -> Result<PhysAddr, isize> {
    let vpn = va.floor();
    if page_table.translate(vpn).is_none() || !page_allows_user_access(page_table, vpn, access) {
        check_page_fault_with_access(va, Some(access.page_fault_access()))?;
    }
    if !page_allows_user_access(page_table, vpn, access) {
        return Err(EFAULT);
    }
    page_table.translate_va(va).ok_or(EFAULT)
}

fn translated_byte_buffer_with_access(
    token: usize,
    ptr: *const u8,
    len: usize,
    access: UserAccess,
) -> Result<Vec<&'static mut [u8]>, isize> {
    let page_table = super::PageTableImpl::from_token(token);
    let mut start = ptr as usize;
    let end = checked_user_range(start, len)?;
    let page_count = if len == 0 {
        0
    } else {
        (start & (PAGE_SIZE - 1))
            .checked_add(len)
            .and_then(|size| size.checked_add(PAGE_SIZE - 1))
            .ok_or(EFAULT)?
            / PAGE_SIZE
    };

    let mut fault_start = start;
    while fault_start < end {
        let start_va = VirtAddr::from(fault_start);
        let mut vpn = start_va.floor();
        if page_table.translate(vpn).is_none()
            || !page_allows_user_access(&page_table, vpn, access)
        {
            check_page_fault_with_access(start_va, Some(access.page_fault_access()))?;
        }
        if !page_allows_user_access(&page_table, vpn, access) {
            return Err(EFAULT);
        }
        vpn.step();
        let mut end_va: VirtAddr = vpn.into();
        end_va = end_va.min(VirtAddr::from(end));
        fault_start = end_va.into();
    }

    let mut v = Vec::with_capacity(page_count);
    while start < end {
        let start_va = VirtAddr::from(start);
        let mut vpn = start_va.floor();
        let ppn = page_table.translate(vpn).ok_or(EFAULT)?;

