impl dyn Socket {
    pub fn alloc(domain: u32, socket_type: u32, protocol: u32) -> GeneralRet<usize> {
        log::info!("[Socket::new] domain: {}", domain);
        let socket_kind = socket_type & 0xf;
        let known_flags = SocketType::SOCK_NONBLOCK.bits() | SocketType::SOCK_CLOEXEC.bits();
        if socket_type & !(0xf | known_flags) != 0 {
            return Err(SyscallErr::EINVAL);
        }
        let cloexec = socket_type & SocketType::SOCK_CLOEXEC.bits() != 0;
        let nonblock = socket_type & SocketType::SOCK_NONBLOCK.bits() != 0;
        match domain as u16 {
            AF_INET | AF_INET6 => {
                let mut flags = OpenFlags::O_RDWR;
                if cloexec {
                    flags |= OpenFlags::O_CLOEXEC;
                }
                if nonblock {
                    flags |= OpenFlags::O_NONBLOCK;
                }
                info!("[Socket::alloc] flags: {:?}", flags);
                if socket_kind == SocketType::SOCK_DGRAM.bits() {
                    if protocol != 0 && protocol != IPPROTO_UDP {
                        return Err(SyscallErr::EPROTONOSUPPORT);
                    }
                    let socket = UdpSocket::new();
                    let socket = Arc::new(socket);
                    // current_process().inner_handler(|proc| {
                    //     let fd = proc.fd_table.alloc_fd()?;
                    //     proc.fd_table.put(fd, FdInfo::new(socket.clone(), flags));
                    //     proc.socket_table.insert(fd, socket);
                    //     Ok(fd)
                    // })
                    let current_tcb = current_task().unwrap();
                    let fd = current_tcb
                        .files
                        .lock()
                        .insert(FileDescriptor::new(cloexec, nonblock, socket.clone()))
                        .unwrap();
                    current_tcb.socket_table.lock().insert(fd, socket);
                    Ok(fd)
                } else if socket_kind == SocketType::SOCK_STREAM.bits() {
                    if protocol != 0 && protocol != IPPROTO_TCP {
                        return Err(SyscallErr::EPROTONOSUPPORT);
                    }
                    let socket = TcpSocket::new();
                    let socket = Arc::new(socket);
                    // current_process().inner_handler(|proc| {
                    //     let fd = proc.fd_table.alloc_fd()?;
                    //     proc.fd_table.put(fd, FdInfo::new(socket.clone(), flags));
                    //     proc.socket_table.insert(fd, socket);
                    //     Ok(fd)
                    // })
                    let current_tcb = current_task().unwrap();
                    let fd = current_tcb
                        .files
                        .lock()
                        .insert(FileDescriptor::new(cloexec, nonblock, socket.clone()))
                        .unwrap();
                    current_tcb.socket_table.lock().insert(fd, socket);
                    Ok(fd)
                } else if socket_kind == 3 {
                    Err(SyscallErr::EPROTONOSUPPORT)
                } else {
                    Err(SyscallErr::ESOCKTNOSUPPORT)
                }
            }
            AF_UNIX => {
                if protocol != 0 {
                    return Err(SyscallErr::EPROTONOSUPPORT);
                }
                let socket_kind = match socket_kind {
                    kind if kind == SocketType::SOCK_STREAM.bits() => SocketType::SOCK_STREAM,
                    kind if kind == SocketType::SOCK_DGRAM.bits() => SocketType::SOCK_DGRAM,
                    kind if kind == SocketType::SOCK_SEQPACKET.bits() => SocketType::SOCK_SEQPACKET,
                    3 => return Err(SyscallErr::EPROTONOSUPPORT),
                    _ => return Err(SyscallErr::ESOCKTNOSUPPORT),
                };
                let (socket, _) = unix::make_unix_socket_pair::<MAX_BUFFER_SIZE>(socket_kind);
                let current_tcb = current_task().unwrap();
                let fd = current_tcb
                    .files
                    .lock()
                    .insert(FileDescriptor::new(cloexec, nonblock, socket.clone()))
                    .unwrap();
