    /// Normal CFS scheduling (SCHED_OTHER/SCHED_NORMAL)
    Normal = 0,
    /// FIFO real-time scheduling (SCHED_FIFO)
    Fifo = 1,
    /// Round-robin real-time scheduling (SCHED_RR)
    RoundRobin = 2,
    /// Batch scheduling (SCHED_BATCH) - treated as CFS
