/// 加载ELF解释器
pub fn load_elf_interp(path: &str) -> Result<&'static [u8], isize> {
    // 只读方式打开指定path的文件
    match ROOT_FD.open(path, OpenFlags::O_RDONLY, false) {
        Ok(file) => {
            // 文件大小小于ELF文件头大小
            if file.get_size() < 4 {
                return Err(ELIBBAD);
            }
            // 读取文件头的前4个字节，即魔数'\x7fELF'
            let mut magic_number = Box::<[u8; 4]>::new([0; 4]);
            // this operation may be expensive... I'm not sure
            // 原作者注释：这个操作可能很昂贵...我不确定
            file.read(Some(&mut 0usize), magic_number.as_mut_slice());
            // 匹配魔数
            match magic_number.as_slice() {
                // 正确情况
                b"\x7fELF" => {
                    // Place the interpreter in the same temporary kernel
                    // window used by exec, but away from the main ELF image.
                    // highest_addr() may point at the direct-map/MMIO edge.
                    let buffer_addr = VirtAddr::from(MMAP_BASE + INTERP_KERNEL_MAP_OFFSET);
                    // 在内核空间的临时地址来分配一个缓冲区
                    let buffer = unsafe {
                        core::slice::from_raw_parts_mut(buffer_addr.0 as *mut u8, file.get_size())
                    };
                    // 获取文件的所有缓存
                    let caches = file.get_all_caches().map_err(|_| EIO)?;
                    // 将缓存内容映射到frame中
                    let frames = caches
                        .iter()
                        .map(|cache| {
                            cache
                                .try_lock()
                                .map(|cache| Frame::InMemory(cache.get_tracker()))
                                .ok_or(EBUSY)
                        })
                        .collect::<Result<Vec<_>, isize>>()?;

                    // 将文件内容映射到内核空间
                    crate::mm::KERNEL_SPACE
                        .lock()
                        .insert_program_area(
                            buffer_addr.into(),
                            crate::mm::MapPermission::R | crate::mm::MapPermission::W,
                            frames,
                        )
                        .map_err(|_| ENOMEM)?;

                    return Ok(buffer);
                }
                // 不是ELF文件
                _ => Err(ELIBBAD),
            }
        }
        Err(errno) => Err(errno),
    }
}

