/// Terminate the calling thread
///
/// # Arguments
/// * `exit_code` - Exit status (only low 8 bits are used)
///
/// # Notes
/// This function does not return - it transfers control to the scheduler.
pub fn sys_exit(exit_code: u32) -> ! {
    exit_current_and_run_next((exit_code & 0xff) << 8);
}

pub fn sys_exit_group(exit_code: u32) -> ! {
    exit_group_and_run_next((exit_code & 0xff) << 8);
}

#[allow(non_camel_case_types)]
#[derive(Debug, Eq, PartialEq, FromPrimitive)]
#[repr(u32)]
pub enum SyslogAction {
    CLOSE = 0,
    OPEN = 1,
    READ = 2,
    READ_ALL = 3,
    READ_CLEAR = 4,
    CLEAR = 5,
    CONSOLE_OFF = 6,
    CONSOLE_ON = 7,
    CONSOLE_LEVEL = 8,
    SIZE_UNREAD = 9,
    SIZE_BUFFER = 10,
    #[default]
    ILLEAGAL,
}

pub fn sys_syslog(type_: u32, buf: *mut u8, len: i32) -> isize {
    const LOG_BUF_LEN: usize = 4096;
    const LOG: &str = "<5>[    0.000000] Linux version 5.10.102.1-microsoft-standard-WSL2 (rtrt@TEAM-NPUCORE) (gcc (Ubuntu 9.4.0-1ubuntu1~20.04) 9.4.0, GNU ld (GNU Binutils for Ubuntu) 2.34) #1 SMP Thu Mar 10 13:31:47 CST 2022";
    let type_ = SyslogAction::from(type_);

    if matches!(
        type_,
        SyslogAction::READ
            | SyslogAction::READ_ALL
            | SyslogAction::READ_CLEAR
            | SyslogAction::CLEAR
            | SyslogAction::CONSOLE_OFF
            | SyslogAction::CONSOLE_ON
            | SyslogAction::CONSOLE_LEVEL
    ) && current_task().unwrap().euid.load(Ordering::Relaxed) != 0
    {
        return EPERM;
    }

    let write_log = |buf: *mut u8, data: &str| -> isize {
        if data.is_empty() {
            return 0;
        }
        let token = current_user_token();
        if copy_to_user_array(token, data.as_ptr(), buf, data.len()).is_err() {
            return EFAULT;
        }
        data.len() as isize
    };

    let read_len = || -> Result<usize, isize> {
        if buf.is_null() {
            return Err(EINVAL);
        }
        if len < 0 {
            return Err(EINVAL);
        }
        Ok(LOG.len().min(len as usize))
    };

    match type_ {
        SyslogAction::CLOSE | SyslogAction::OPEN => SUCCESS,
        SyslogAction::READ => match read_len() {
            Ok(len) => write_log(buf, &LOG[..len]),
            Err(errno) => errno,
        },
        SyslogAction::READ_ALL | SyslogAction::READ_CLEAR => match read_len() {
            Ok(len) => write_log(buf, &LOG[LOG.len() - len..]),
            Err(errno) => errno,
        },
        SyslogAction::CLEAR | SyslogAction::CONSOLE_OFF | SyslogAction::CONSOLE_ON => SUCCESS,
        SyslogAction::CONSOLE_LEVEL => {
            match crate::fs::dev::proc::set_kernel_printk_console_level(len) {
                Ok(()) => SUCCESS,
                Err(errno) => errno,
            }
        }
        SyslogAction::SIZE_UNREAD => LOG.len() as isize,
        SyslogAction::SIZE_BUFFER => LOG_BUF_LEN as isize,
        SyslogAction::ILLEAGAL => EINVAL,
    }
}

