        let zram_id = match self.recycled.pop() {
            Some(zram_id) => zram_id as usize,
            None => {
                if self.tail as usize == self.compressed.len() {
                    // 空间不足，返回错误
                    return Err(ZramError::NoSpace);
                } else {
                    // 更新tail
                    self.tail += 1;
                    (self.tail - 1) as usize
                }
