        if zram_id >= self.compressed.len() {
            return Err(ZramError::InvalidIndex);
        }
        match &self.compressed[zram_id] {
            Some(compressed_data) => Ok(compressed_data),
            None => Err(ZramError::NotAllocated),
        }
