        if zram_id >= self.compressed.len() {
            return Err(ZramError::InvalidIndex);
        }
        // 刚好等于最后一个分配的id
        if zram_id == (self.tail - 1) as usize {
            // 回退tail
            self.tail = zram_id as u16;
        } else {
            // 加入回收列表
            self.recycled.push(zram_id as u16);
