fn proc_task_state(status: TaskStatus) -> (char, &'static str) {
    match status {
        TaskStatus::Ready | TaskStatus::Running => ('R', "running"),
        TaskStatus::Interruptible => ('S', "sleeping"),
        TaskStatus::Zombie => ('Z', "zombie"),
        TaskStatus::Stopped => ('T', "stopped"),
    }
}

fn proc_task_state_for(task: &TaskControlBlock) -> (char, &'static str) {
    let inner = task.acquire_inner_lock();
    proc_task_state(inner.task_status)
}

impl ProcSelfStatus {
    pub fn new() -> Self {
        Self {
            offset: Mutex::new(0),
        }
    }

    fn content() -> String {
        let task = current_task().unwrap();
        let pid = task.pid.0;
        let tgid = task.tgid;
        let ppid = task.parent_tgid.load(Ordering::Relaxed);
        let uid = task.uid.load(Ordering::Relaxed);
        let euid = task.euid.load(Ordering::Relaxed);
        let suid = task.suid.load(Ordering::Relaxed);
        let fsuid = task.fsuid.load(Ordering::Relaxed);
        let gid = task.gid.load(Ordering::Relaxed);
        let egid = task.egid.load(Ordering::Relaxed);
        let sgid = task.sgid.load(Ordering::Relaxed);
        let fsgid = task.fsgid.load(Ordering::Relaxed);
        let no_new_privs = task.no_new_privs.load(Ordering::Relaxed);
        let cap_amb = task.ambient_caps.load(Ordering::Relaxed);
        let rss_kb = task.current_rss_kb();
        let (state_code, state_name) = proc_task_state_for(&task);
        format!(
            "Name:\tltp\nState:\t{} ({})\nTgid:\t{}\nPid:\t{}\nPPid:\t{}\nUid:\t{} {} {} {}\nGid:\t{} {} {} {}\nCapAmb:\t{:016x}\nNoNewPrivs:\t{}\nVmHWM:\t{} kB\nVmRSS:\t{} kB\nVmSwap:\t0 kB\n",
            state_code,
            state_name,
            tgid,
            pid,
            ppid,
            uid,
            euid,
            suid,
            fsuid,
            gid,
            egid,
            sgid,
            fsgid,
            cap_amb,
            no_new_privs,
            rss_kb,
            rss_kb
        )
    }
}

