impl ProcSelfPagemap {
    pub fn new() -> Self {
        Self {
            offset: Mutex::new(0),
        }
    }

    fn entry_for_vpn(vpn: usize) -> u64 {
        const PAGE_PRESENT: u64 = 1 << 63;
        let Some(task) = current_task() else {
            return 0;
        };
        if task.vm.lock().translate(VirtPageNum(vpn)).is_some() {
            PAGE_PRESENT
        } else {
            0
        }
    }

    fn fill_bytes(start: usize, bytes: &mut [u8]) {
        let mut absolute = start;
        let mut cached_vpn = usize::MAX;
        let mut cached_entry = [0u8; 8];
        for byte in bytes.iter_mut() {
            let vpn = absolute / 8;
            if vpn != cached_vpn {
                cached_vpn = vpn;
                cached_entry = Self::entry_for_vpn(vpn).to_le_bytes();
            }
            *byte = cached_entry[absolute & 7];
            absolute = absolute.saturating_add(1);
        }
    }

    fn read_at(&self, offset_arg: Option<usize>, mut buf: UserBuffer) -> usize {
        let start = offset_arg.unwrap_or_else(|| {
            let mut guard = self.offset.lock();
            let start = *guard;
            *guard = (*guard).saturating_add(buf.len());
            start
        });
        let mut absolute = start;
        let mut read_len = 0usize;
        for buffer in buf.buffers.iter_mut() {
            Self::fill_bytes(absolute, buffer);
            absolute = absolute.saturating_add(buffer.len());
            read_len = read_len.saturating_add(buffer.len());
        }
        read_len
    }
}

