bitflags! {
    /// Page Table Entry flags
    pub struct PTEFlags: u8 {
    /// Valid Bit
        const V = 1 << 0;
    /// Readable Bit
        const R = 1 << 1;
    /// Writable Bit
        const W = 1 << 2;
    /// Executable Bit
        const X = 1 << 3;
    /// User Space Bit, true if it can be accessed from user space.
        const U = 1 << 4;
        const G = 1 << 5;
        const A = 1 << 6;
    /// Dirty Bit, true if it is modified.
        const D = 1 << 7;
    }
}

/// Page Table Entry
#[derive(Copy, Clone)]
#[repr(C)]
pub struct Sv39PageTableEntry {
    pub bits: usize,
}

impl Sv39PageTableEntry {
    const PPN_MASK: usize = ((1usize << 44) - 1) << 10;
    fn leaf_flags(flags: MapPermission) -> PTEFlags {
        let mut pte_flags = PTEFlags::from_bits(flags.bits()).unwrap();
        // Sv39 reserves PTEs with W=1,R=0. User VMAs can still model
        // PROT_WRITE without PROT_READ logically; the hardware leaf must
        // carry R so the entry is valid and writes can complete.
        if pte_flags.contains(PTEFlags::W) {
            pte_flags |= PTEFlags::R;
        }
        pte_flags
    }
    pub fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        Sv39PageTableEntry {
            bits: ppn.0 << 10 | flags.bits as usize,
        }
    }
    pub fn empty() -> Self {
        Sv39PageTableEntry { bits: 0 }
    }
    pub fn ppn(&self) -> PhysPageNum {
        ((self.bits & Self::PPN_MASK) >> 10).into()
    }
    pub fn flags(&self) -> PTEFlags {
        PTEFlags::from_bits(self.bits as u8).unwrap()
    }
    pub fn is_valid(&self) -> bool {
        (self.flags() & PTEFlags::V) != PTEFlags::empty()
    }
    pub fn is_dirty(&self) -> bool {
        (self.flags() & PTEFlags::D) != PTEFlags::empty()
    }
    pub fn readable(&self) -> bool {
        (self.flags() & PTEFlags::R) != PTEFlags::empty()
    }
    pub fn writable(&self) -> bool {
        (self.flags() & PTEFlags::W) != PTEFlags::empty()
    }
    pub fn executable(&self) -> bool {
        (self.flags() & PTEFlags::X) != PTEFlags::empty()
    }
    pub fn user_accessible(&self) -> bool {
        (self.flags() & PTEFlags::U) != PTEFlags::empty()
    }
    pub fn clear_access(&mut self) {
        self.bits &= !(PTEFlags::A.bits() as usize);
    }
    pub fn clear_dirty(&mut self) {
        self.bits &= !(PTEFlags::D.bits() as usize);
    }
    pub fn revoke_read(&mut self) {
        if !self.writable() {
            self.bits &= !(PTEFlags::R.bits() as usize);
        }
    }
    pub fn revoke_write(&mut self) {
        self.bits &= !(PTEFlags::W.bits() as usize);
    }
    pub fn revoke_execute(&mut self) {
        self.bits &= !(PTEFlags::X.bits() as usize);
    }

