fn insert_file_fd(file: Arc<dyn File>, cloexec: bool, nonblock: bool, opath: bool) -> isize {
    let task = current_task().unwrap();
    let mut fd_table = task.files.lock();
    match fd_table.insert(FileDescriptor::new(cloexec, nonblock, file).with_opath(opath)) {
        Ok(fd) => {
            task.socket_table.lock().take(fd);
            fd as isize
        }
        Err(errno) => errno,
    }
}

fn insert_anon_fd(kind: AnonFdKind, cloexec: bool, nonblock: bool, opath: bool) -> isize {
    insert_file_fd(make_anon_file(kind), cloexec, nonblock, opath)
}

fn insert_mem_fd(allow_sealing: bool, cloexec: bool) -> isize {
    insert_file_fd(make_mem_file(allow_sealing), cloexec, false, false)
}

fn insert_pid_fd(target: Arc<TaskControlBlock>) -> isize {
    insert_file_fd(make_pid_file(target), true, false, false)
}

fn cloexec_nonblock_from_flags(flags: u32, allowed_extra: u32) -> Result<(bool, bool), isize> {
    let cloexec = OpenFlags::O_CLOEXEC.bits();
    let nonblock = OpenFlags::O_NONBLOCK.bits();
    if flags & !(cloexec | nonblock | allowed_extra) != 0 {
        return Err(EINVAL);
    }
    Ok((flags & cloexec != 0, flags & nonblock != 0))
}

fn validate_user_string_ptr(ptr: *const u8) -> isize {
    if ptr.is_null() {
        return EFAULT;
    }
    match translated_str(current_user_token(), ptr) {
        Ok(_) => SUCCESS,
        Err(errno) => errno,
    }
}

