const DEFAULT_REALTIME_BASE_SEC: usize = 1_767_225_600; // 2026-01-01 00:00:00 UTC
static REALTIME_OFFSET_NS: AtomicI64 = AtomicI64::new(0);

fn default_realtime_base_ns() -> i128 {
    (DEFAULT_REALTIME_BASE_SEC as i128) * (NSEC_PER_SEC as i128)
}

fn realtime_ns() -> usize {
    let ns = default_realtime_base_ns()
        + (get_time_ns() as i128)
        + (REALTIME_OFFSET_NS.load(AtomicOrdering::Relaxed) as i128);
    if ns <= 0 {
        0
    } else if ns > usize::MAX as i128 {
        usize::MAX
    } else {
        ns as usize
    }
}

pub fn set_realtime(timespec: TimeSpec) {
    let target_ns = (timespec.tv_sec as i128) * (NSEC_PER_SEC as i128) + (timespec.tv_nsec as i128);
    let base_now_ns = default_realtime_base_ns() + (get_time_ns() as i128);
    let offset = target_ns - base_now_ns;
    let offset = offset.clamp(i64::MIN as i128, i64::MAX as i128) as i64;
    REALTIME_OFFSET_NS.store(offset, AtomicOrdering::Relaxed);
}

/// Return current time measured by seconds.
pub fn get_time_sec() -> usize {
    let freq = get_clock_freq();
    if freq == 0 {
        return 0;
    }
    let i = get_time() / freq;
    //log::info!("[timer.rs] get_time(): {},sec: {}", get_time(), i);
    i
}

/// Return current time measured by ms.
pub fn get_time_ms() -> usize {
    let freq = get_clock_freq();
    if freq == 0 {
        return 0;
    }
    let tick = get_time();
    let i = tick / freq * MSEC_PER_SEC + tick % freq * MSEC_PER_SEC / freq;
    //log::info!("[timer.rs] get_time(): {},ms: {}", get_time(), i);
    i
}

/// Return current time measured by us.
pub fn get_time_us() -> usize {
    let freq = get_clock_freq();
    if freq == 0 {
        return 0;
    }
    let tick = get_time();
    let i = tick / freq * USEC_PER_SEC + tick % freq * USEC_PER_SEC / freq;
    //log::info!("[timer.rs] get_time(): {},us: {}", get_time(), i);
    i
}

/// Return current time measured by nano seconds.
pub fn get_time_ns() -> usize {
    let freq = get_clock_freq();
    if freq == 0 {
        return 0;
    }
    let tick = get_time();
    let i = tick / freq * NSEC_PER_SEC + tick % freq * NSEC_PER_SEC / freq;
    //log::info!("[timer.rs] get_time(): {},ns: {}", get_time(), i);
    i
}

pub fn current_time_duration() -> Duration {
    Duration::from_micros(get_time_us() as u64)
}

