/// 任务的激活状态跟踪器
pub struct ActiveTracker {
    /// 存储激活状态的位图
    bitmap: Vec<u64>,
}

#[cfg(feature = "oom_handler")]
#[allow(unused)]
impl ActiveTracker {
    /// 默认大小为128
    pub const DEFAULT_SIZE: usize = SYSTEM_TASK_LIMIT;
    /// 构造函数
    pub fn new() -> Self {
        // 计算位图长度，向上取整
        let len = (Self::DEFAULT_SIZE + 63) / 64;
        // 初始化位图
        let mut bitmap = Vec::with_capacity(len);
        // 位图全部置0
        bitmap.resize(len, 0);
        Self { bitmap }
    }
    fn word_index(pid: usize) -> usize {
        pid / 64
    }
    fn bit_mask(pid: usize) -> u64 {
        1 << (pid % 64)
    }
    fn ensure_pid(&mut self, pid: usize) {
        let index = Self::word_index(pid);
        if index >= self.bitmap.len() {
            self.bitmap.resize(index + 1, 0);
        }
    }
    /// 检查制定pid的任务是否处于激活状态
    pub fn check_active(&self, pid: usize) -> bool {
        self.bitmap
            .get(Self::word_index(pid))
            .map_or(false, |word| (*word & Self::bit_mask(pid)) != 0)
    }
    /// 检查制定pid的任务是否处于非激活状态
    pub fn check_inactive(&self, pid: usize) -> bool {
        !self.check_active(pid)
    }
    /// 标记指定pid的任务为激活状态
    pub fn mark_active(&mut self, pid: usize) {
        self.ensure_pid(pid);
        self.bitmap[Self::word_index(pid)] |= Self::bit_mask(pid)
    }
    /// 标记指定pid的任务为非激活状态
    pub fn mark_inactive(&mut self, pid: usize) {
        if let Some(word) = self.bitmap.get_mut(Self::word_index(pid)) {
            *word &= !Self::bit_mask(pid);
        }
    }
}

