/// VirtIO block device sector size (512 bytes)
const VIRTIO_BLK_SIZE: usize = 512;

// QEMU virt 平台的 VirtIO-MMIO slot 基址（每个 0x1000）。
// 不能硬编码只用第一个 slot：如果先创建了 net，再创建 blk，blk 可能落在后续 slot。
const VIRTIO_MMIO_SLOTS: &[usize] = &[
    0x1000_1000,
    0x1000_2000,
    0x1000_3000,
    0x1000_4000,
    0x1000_5000,
    0x1000_6000,
    0x1000_7000,
    0x1000_8000,
];

pub struct VirtIOBlock(Mutex<VirtIOBlk<VirtioHal, MmioTransport>>);

impl BlockDevice for VirtIOBlock {
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        // Convert filesystem block to virtio sectors
        let sectors_per_block = BLOCK_SZ / VIRTIO_BLK_SIZE;
        let start_sector = block_id * sectors_per_block;
        for (i, chunk) in buf.chunks_mut(VIRTIO_BLK_SIZE).enumerate() {
            self.0
                .lock()
                .read_blocks(start_sector + i, chunk)
                .expect("Error when reading VirtIOBlk");
        }
    }
    fn write_block(&self, block_id: usize, buf: &[u8]) {
        // Convert filesystem block to virtio sectors
        let sectors_per_block = BLOCK_SZ / VIRTIO_BLK_SIZE;
        let start_sector = block_id * sectors_per_block;
        for (i, chunk) in buf.chunks(VIRTIO_BLK_SIZE).enumerate() {
            self.0
                .lock()
                .write_blocks(start_sector + i, chunk)
                .expect("Error when writing VirtIOBlk");
        }
    }
}

impl VirtIOBlock {
    #[allow(unused)]
    pub fn new() -> Self {
        let mut chosen: Option<MmioTransport> = None;
        for &base in VIRTIO_MMIO_SLOTS {
            let Some(header) = NonNull::new(base as *mut VirtIOHeader) else {
                continue;
            };
            // 可能遇到空 slot（device_id=0）或非 VirtIO 区域，直接跳过即可。
            let Ok(mut transport) = (unsafe { MmioTransport::new(header) }) else {
                continue;
            };
            if transport.device_type() == DeviceType::Block {
                chosen = Some(transport);
                break;
            }
        }
        let transport = chosen.expect("No VirtIO-MMIO block device found");
        Self(Mutex::new(
            VirtIOBlk::<VirtioHal, MmioTransport>::new(transport).unwrap(),
        ))
    }
}

