fn read_socklen_value(addrlen: usize) -> Result<u32, isize> {
    if addrlen == 0 {
        return Err(EFAULT);
    }
    let token = current_task().unwrap().get_user_token();
    let len_ref = translated_ref(token, addrlen as *const u32).map_err(|_| EFAULT)?;
    let len = *len_ref;
    if (len as i32) < 0 {
        return Err(EINVAL);
    }
    Ok(len)
}

